import{_ as e,c as t,a as s,b as i,d as p,r as l,o}from"./app-DxT-J_20.js";const c={};function d(u,n){const a=l("DateMeta");return o(),t("div",null,[n[0]||(n[0]=s("h1",{id:"_14-exception-handling-and-event-handling",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#_14-exception-handling-and-event-handling"},[s("span",null,"14. Exception Handling and Event Handling")])],-1)),i(a),n[1]||(n[1]=p(`<h2 id="exception-handling-and-event-handling" tabindex="-1"><a class="header-anchor" href="#exception-handling-and-event-handling"><span>Exception Handling and Event Handling</span></a></h2><ul><li>What do we study in this chapter?</li><li>Introduction to Exception Handling</li><li>Exception Handling in Ada</li><li>Exception Handling in C++</li><li>Exception Handling in Java</li><li>Exception Handling in Python and Ruby</li><li>Introduction to Event Handling</li><li>Event Handling in Java</li><li>Event Handling in C#</li><li>Introduction to Exception and Event Handling</li><li>Both can occur at time that cannot be predefined</li><li>Both are best handled with special language constructs and processes</li><li>[Exception handling]</li><li>HW, SW- detectable exception</li><li>Handler</li><li>Raising of exception</li><li>Design issue- binding to handler, continuation, default handler, exception disabling</li><li>Three programming language (Ada, C++, Java)</li><li>[Event handling]</li><li>Basic concept</li><li>Java and C# examples</li></ul><h2 id="introduction-to-exception-handling" tabindex="-1"><a class="header-anchor" href="#introduction-to-exception-handling"><span>Introduction to Exception Handling</span></a></h2><ul><li>In a language without exception handling</li><li>When an exception occurs, control goes to the operating system, where a message is displayed and the program is terminated</li><li>In a language with exception handling</li><li>Programs are allowed to trap some exceptions, thereby providing the possibility of fixing the problem and continuing</li></ul><h2 id="basic-concepts" tabindex="-1"><a class="header-anchor" href="#basic-concepts"><span>Basic Concepts</span></a></h2><ul><li>Many languages allow programs to trap input/output errors (including EOF)</li><li>An exception is any unusual event, either erroneous or not, detectable by either hardware or software, that may require special processing</li><li>The special processing that may be required after detection of an exception is called exception handling</li><li>The exception handling code unit is called an exception handler</li></ul><h2 id="exception-handling-alternatives" tabindex="-1"><a class="header-anchor" href="#exception-handling-alternatives"><span>Exception Handling Alternatives</span></a></h2><ul><li>An exception is raised when its associated event occurs</li><li>Different kinds of exceptions require different exception handlers</li><li>A language that does not have exception handling capabilities can still define, detect, raise, and handle exceptions (user defined, software detected)</li><li>Alternatives:</li><li>[1] Send an auxiliary parameter or use the return value to indicate the return status of a subprogram</li><li>[2] Pass a label parameter to all subprograms (error return is to the passed label)</li><li>Possible only in languages that allow labels</li><li>Can return to a different point in the caller if an exception occurs</li><li>[3] Pass an exception handling subprogram to all subprograms</li><li>Send a handler subprogram with every call to every subprogram</li></ul><h2 id="advantages-of-built-in-exception-handling" tabindex="-1"><a class="header-anchor" href="#advantages-of-built-in-exception-handling"><span>Advantages of Built-in Exception Handling</span></a></h2><ul><li>Error detection code is tedious to write and it clutters the program</li><li>Exception handling encourages programmers to consider many different possible errors</li><li>Exception propagation allows a high level of reuse of exception handling code</li><li>Dealing with nonerroneous but unusual situations can be simplified with exception handling</li></ul><h2 id="design-issues" tabindex="-1"><a class="header-anchor" href="#design-issues"><span>Design Issues</span></a></h2><ul><li>How and where are exception handlers specified and what is their scope?</li><li>How is an exception occurrence bound to an exception handler?</li><li>How the same exception raised at different points can be bound to different handlers</li><li>Whether to propagate the exception to some other unit and, if so, where</li><li>Can information about the exception be passed to the handler?</li><li>Where does execution continue, if at all, after an exception handler completes its execution? (termination vs. resumption)</li><li>Is some form of finalization provided?</li><li>How are user-defined exceptions specified?</li><li>Should there be default exception handlers for programs that do not provide their own?</li><li>Can predefined exceptions be explicitly raised?</li><li>Are hardware-detectable errors treated as exceptions that can be handled?</li><li>Are there any predefined exceptions?</li><li>How can exceptions be disabled, if at all?</li></ul><h2 id="exception-handling-control-flow" tabindex="-1"><a class="header-anchor" href="#exception-handling-control-flow"><span>Exception Handling Control Flow</span></a></h2><h2 id="exception-handling-in-ada" tabindex="-1"><a class="header-anchor" href="#exception-handling-in-ada"><span>Exception Handling in Ada</span></a></h2><ul><li>Handlers can be included in blocks or bodies of subprograms, packages, or tasks</li><li>Gathered together in an exception clause</li><li>Must be placed at the end of the block or unit</li><li>Usual form of an exception clause</li></ul><div class="language-ada line-numbers-mode" data-highlighter="prismjs" data-ext="ada"><pre><code class="language-ada"><span class="line"><span class="token keyword">begin</span></span>
<span class="line"><span class="token comment">-- the block or unit body --</span></span>
<span class="line"><span class="token keyword">exception</span></span>
<span class="line"><span class="token keyword">when</span> <span class="token variable">exception_name1</span> <span class="token operator">=&gt;</span></span>
<span class="line"><span class="token comment">-- first handler --</span></span>
<span class="line"><span class="token keyword">when</span> <span class="token variable">exception_name2</span> <span class="token operator">=&gt;</span></span>
<span class="line"><span class="token comment">-- second handler --</span></span>
<span class="line"><span class="token comment">-- other handlers --</span></span>
<span class="line"><span class="token keyword">end</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="binding-exceptions-to-handlers" tabindex="-1"><a class="header-anchor" href="#binding-exceptions-to-handlers"><span>Binding Exceptions to Handlers</span></a></h2><ul><li>When block or unit that raises an exception includes a handler</li><li>Exception is statically bound to that handler</li><li>When procedure is raised</li><li>No handler → implicitly propagated to calling program (dynamic ancestor) until the main procedure if necessary</li><li>Still no → terminate</li><li>When exception is raised in a package body</li><li>If no handler in body → propagated to declaration section</li><li>If package happens to be a library unit → terminate</li><li>When exception is raised at the outermost level in a task body</li><li>If no, not propagated (too complex) (<code>Tasking_Error</code> is raised)</li></ul><h2 id="continuation" tabindex="-1"><a class="header-anchor" href="#continuation"><span>Continuation</span></a></h2><ul><li>If exception is not handled -&gt; terminated</li><li>Control never returns implicitly to the raising block</li><li>Simply continues after the exception clause</li><li>Cannot be continued or resumed</li><li>Can retry with loop block</li></ul><div class="language-ada line-numbers-mode" data-highlighter="prismjs" data-ext="ada"><pre><code class="language-ada"><span class="line"><span class="token punctuation">..</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token keyword">type</span> <span class="token variable">Age_Type</span> <span class="token keyword">is</span> <span class="token keyword">range</span> <span class="token number">0</span><span class="token punctuation">..</span><span class="token number">125</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">type</span> <span class="token variable">Age_List_Type</span> <span class="token keyword">is</span> <span class="token keyword">array</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">..</span><span class="token number">4</span><span class="token punctuation">)</span> <span class="token keyword">of</span> <span class="token variable">Age_Type</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">package</span> <span class="token variable">Age_IO</span> <span class="token keyword">is</span> <span class="token keyword">new</span> <span class="token variable">Integer_IO</span> <span class="token punctuation">(</span><span class="token variable">Age_Type</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">use</span> <span class="token variable">Age_IO</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token variable">Age_List</span> <span class="token punctuation">:</span> <span class="token variable">Age_List_Type</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">..</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token keyword">begin</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token variable">Age_Count</span> <span class="token keyword">in</span> <span class="token number">1</span><span class="token punctuation">..</span><span class="token number">4</span> <span class="token keyword">loop</span></span>
<span class="line"><span class="token keyword">loop</span> <span class="token comment">-- loop for repetition when exceptions occur Except_Blk:</span></span>
<span class="line"><span class="token keyword">begin</span> <span class="token comment">-- compound to encapsulate exception handling</span></span>
<span class="line"><span class="token variable">Put_Line</span><span class="token punctuation">(</span><span class="token string">&quot;Enter an integer in the range 0..125&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token variable">Get</span><span class="token punctuation">(</span><span class="token variable">Age_List</span><span class="token punctuation">(</span><span class="token variable">Age_Count</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">exit</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">exception</span></span>
<span class="line"><span class="token keyword">when</span> <span class="token variable">Data_Error</span> <span class="token operator">=&gt;</span> <span class="token comment">-- Input string is not a number</span></span>
<span class="line"><span class="token variable">Put_Line</span><span class="token punctuation">(</span><span class="token string">&quot;Illegal numeric value&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token variable">Put_Line</span><span class="token punctuation">(</span><span class="token string">&quot;Please try again&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">when</span> <span class="token variable">Constraint_Error</span> <span class="token operator">=&gt;</span> <span class="token comment">-- Input is &lt; 0 or &gt; 125</span></span>
<span class="line"><span class="token variable">Put_Line</span><span class="token punctuation">(</span><span class="token string">&quot;Input number is out of range&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token variable">Put_Line</span><span class="token punctuation">(</span><span class="token string">&quot;Please try again&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">end</span> <span class="token variable">Except_Blk</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">end</span> <span class="token keyword">loop</span><span class="token punctuation">;</span> <span class="token comment">-- end of the infinite loop to repeat input</span></span>
<span class="line"><span class="token comment">-- when there is an exception</span></span>
<span class="line"><span class="token keyword">end</span> <span class="token keyword">loop</span><span class="token punctuation">;</span> <span class="token comment">-- end of for Age_Count in 1..4 loop</span></span>
<span class="line"><span class="token punctuation">..</span><span class="token punctuation">.</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="other-design-choices" tabindex="-1"><a class="header-anchor" href="#other-design-choices"><span>Other design choices</span></a></h2><ul><li>Default package, Standard</li><li><code>Constraint_Error</code></li><li><code>Program_Error</code></li><li><code>Storage_Error</code></li><li><code>Tasking_Error</code></li><li>User-defined exception (explicitly raised)</li><li><code>exception_name_list : exception</code></li><li><code>raise [exception_name]</code></li><li><code>raise</code> without naming within handler → reraise the same exception</li><li>Suspending a specified check in associated block</li><li><code>pragma Suppress(check_name)</code></li></ul><h2 id="example" tabindex="-1"><a class="header-anchor" href="#example"><span>Example</span></a></h2><ul><li>[Problem] Program computes and prints a distribution of input grades by using an array of counters</li><li>[Possible exception]</li><li>Negative input</li><li>Subscript range</li><li>Code to handle invalid input grades is in its own local block → This allows the program to continue after such exceptions are handled</li></ul><h2 id="evaluation" tabindex="-1"><a class="header-anchor" href="#evaluation"><span>Evaluation</span></a></h2><ul><li>Several problems</li><li>Allow propagation to outer scope that is not visible</li><li>Not always possible to determine the origin of propagated exceptions</li><li>Inadequacy of exception handling for tasks</li><li>Exception handling was not extended to deal with the new constructs (OOP in Ada 95)</li></ul><h2 id="exception-handling-in-c" tabindex="-1"><a class="header-anchor" href="#exception-handling-in-c"><span>Exception Handling in C++</span></a></h2><ul><li>Added to C++ in 1990</li><li>Design is based on that of CLU, Ada, and ML</li><li>No predefined exceptions in C++ (other than in its standard libraries)</li><li>Exceptions are user or library defined and explicitly raised</li></ul><h2 id="exception-handlers-form" tabindex="-1"><a class="header-anchor" href="#exception-handlers-form"><span>Exception Handlers Form:</span></a></h2><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code class="language-cpp"><span class="line"><span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">//code that is expected to raise an exception</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">catch</span> <span class="token punctuation">(</span>formal parameter<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">// handler code</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token keyword">catch</span> <span class="token punctuation">(</span>formal parameter<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">// handler code</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="the-catch-function" tabindex="-1"><a class="header-anchor" href="#the-catch-function"><span>The catch Function</span></a></h2><ul><li><code>catch</code> is the name of all handlers--it is an overloaded name, so the formal parameter of each must be unique</li><li>The formal parameter need not have a variable</li><li>It can be simply a type name to distinguish the handler it is in from others</li><li>The formal parameter can be used to transfer information to the handler</li><li>The formal parameter can be an ellipsis, in which case it handles all exceptions not yet handled</li></ul><h2 id="throwing-exceptions" tabindex="-1"><a class="header-anchor" href="#throwing-exceptions"><span>Throwing Exceptions</span></a></h2><ul><li>Exceptions are all raised explicitly by the statement:</li><li><code>throw [expression];</code></li><li>The brackets are metasymbols</li><li>A <code>throw</code> without an operand can only appear in a handler; when it appears, it simply re-raises the exception, which is then handled elsewhere</li><li>The type of the expression disambiguates the intended handler</li><li>Matching handler is done sequentially</li><li>If any other match precedes, exact matched handler is not used</li></ul><h2 id="unhandled-exceptions" tabindex="-1"><a class="header-anchor" href="#unhandled-exceptions"><span>Unhandled Exceptions</span></a></h2><ul><li>An unhandled exception is propagated to the caller of the function in which it is raised</li><li>This propagation continues to the main function</li><li>If no handler is found, the default handler is called</li></ul><h2 id="continuation-1" tabindex="-1"><a class="header-anchor" href="#continuation-1"><span>Continuation</span></a></h2><ul><li>After a handler completes its execution, control flows to the first statement after the last handler in the sequence of handlers of which it is an element</li></ul><h2 id="other-design-choices-1" tabindex="-1"><a class="header-anchor" href="#other-design-choices-1"><span>Other design choices</span></a></h2><ul><li>All exceptions are user-defined</li><li>The default handler, <code>unexpected</code>, simply terminates the program; <code>unexpected</code> can be redefined by the user</li><li>Functions can list the exceptions they may raise (<code>int fun() throw (int, char *) { . . . }</code>)</li><li>Without a specification, a function can raise any exception (the <code>throw</code> clause)</li><li>No predefined exception</li><li>But, standard libraries (<code>out_of_range</code>, <code>overflow_error</code>) can be used</li></ul><h2 id="evaluation-1" tabindex="-1"><a class="header-anchor" href="#evaluation-1"><span>Evaluation</span></a></h2><ul><li>There are no predefined exceptions</li><li>It is odd that exceptions are not named and that hardware- and system software detectable exceptions cannot be handled</li><li>Binding exceptions to handlers through the type of the parameter certainly does not promote readability</li><li>Better to define classes for exceptions with meaningful names in a meaningful hierarchy</li></ul><h2 id="exception-handling-in-java" tabindex="-1"><a class="header-anchor" href="#exception-handling-in-java"><span>Exception Handling in Java</span></a></h2><ul><li>Based on that of C++, but more in line with OOP philosophy</li><li>There is a collection of predefined exceptions (implicitly raised by JVM)</li><li>All exceptions are objects of classes that are descendants of the <code>Throwable</code> class</li></ul><h2 id="classes-of-exceptions" tabindex="-1"><a class="header-anchor" href="#classes-of-exceptions"><span>Classes of Exceptions</span></a></h2><ul><li>The Java library includes two predefined subclasses of <code>Throwable</code> :</li><li><code>Error</code></li><li>Thrown by the Java interpreter (Java run-time system) for events such as heap overflow</li><li>Never handled by user programs</li><li><code>Exception</code></li><li>User-defined exceptions are usually subclasses of this</li><li>Has two predefined subclasses, <code>IOException</code> and <code>RuntimeException</code></li><li>(e.g., <code>ArrayIndexOutOfBoundsException</code> and <code>NullPointerException</code>)</li></ul><h2 id="java-exception-handlers" tabindex="-1"><a class="header-anchor" href="#java-exception-handlers"><span>Java Exception Handlers</span></a></h2><ul><li>Like those of C++, except every <code>catch</code> requires a named parameter and all parameters must be descendants of <code>Throwable</code></li><li>Syntax of <code>try</code> clause is exactly that of C++</li><li>Exceptions are thrown with <code>throw</code>, as in C++, but often the <code>throw</code> includes the <code>new</code> operator to create the object, as in: <code>throw new MyException();</code></li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">class</span> <span class="token class-name">MyException</span> <span class="token keyword">extends</span> <span class="token class-name">Exception</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token class-name">MyException</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token class-name">MyException</span><span class="token punctuation">(</span><span class="token class-name">String</span> message<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">super</span> <span class="token punctuation">(</span>message<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">MyException</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">MyException</span> <span class="token punctuation">(</span><span class="token string">&quot;a message to specify the location of the error&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name">MyException</span> myExceptionObject <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">MyException</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">throw</span> myExceptionObject<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="binding-exceptions-to-handlers-1" tabindex="-1"><a class="header-anchor" href="#binding-exceptions-to-handlers-1"><span>Binding Exceptions to Handlers</span></a></h2><ul><li>Binding an exception to a handler is simpler in Java than it is in C++</li><li>An exception is bound to the first handler with a parameter is the same class as the thrown object or an ancestor of it</li><li>An exception can be handled and rethrown by including a <code>throw</code> in the handler (a handler could also throw a different exception)</li></ul><h2 id="continuation-2" tabindex="-1"><a class="header-anchor" href="#continuation-2"><span>Continuation</span></a></h2><ul><li>If no handler is found in the <code>try</code> construct, the search is continued in the nearest enclosing <code>try</code> construct, etc.</li><li>If no handler is found in the method, the exception is propagated to the method’s caller</li><li>If no handler is found (all the way to main), the program is terminated</li><li>To insure that all exceptions are caught, a handler can be included in any <code>try</code> construct that catches all exceptions</li><li>Simply use an <code>Exception</code> class parameter</li><li>Of course, it must be the last in the <code>try</code> construct</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">Exception</span> genericObject<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="checked-and-unchecked-exceptions" tabindex="-1"><a class="header-anchor" href="#checked-and-unchecked-exceptions"><span>Checked and Unchecked Exceptions</span></a></h2><ul><li>The Java <code>throws</code> clause is quite different from the <code>throw</code> clause of C++</li><li>Exceptions of class <code>Error</code> and <code>RuntimeException</code> and all of their descendants are called unchecked exceptions; all other exceptions are called checked exceptions</li><li>Unchecked exceptions are never a concern of the compiler</li><li>Checked exceptions that may be thrown by a method must be either:</li><li>Listed in the <code>throws</code> clause, or</li><li>Handled in the method</li><li>Checking this at compile time differs from C++, in which it is done at run time</li></ul><h2 id="other-design-choices-2" tabindex="-1"><a class="header-anchor" href="#other-design-choices-2"><span>Other Design Choices</span></a></h2><ul><li>A method cannot declare more exceptions in its <code>throws</code> clause than the method it overrides</li><li>A method that does not directly throw a particular exception, but calls another method that could throw that exception, must list the exception in its <code>throws</code> clause</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">void</span> <span class="token function">buildDist</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">IOException</span> <span class="token punctuation">{</span></span>
<span class="line">…</span>
<span class="line">in<span class="token punctuation">.</span><span class="token function">readLine</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// could throw IO exception</span></span>
<span class="line">…</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>A method that does not include a <code>throws</code> clause cannot propagate any checked exception</li><li>In C++, function without a <code>throw</code> clause can throw any exception</li><li>A method that calls a method that lists a particular checked exception in its <code>throws</code> clause has three alternatives for dealing with that exception:</li><li>[1] Catch and handle the exception</li><li>[2] Catch the exception and throw an exception that is listed in its own <code>throws</code> clause</li><li>[3] Declare it in its <code>throws</code> clause and do not handle it</li></ul><h2 id="the-finally-clause" tabindex="-1"><a class="header-anchor" href="#the-finally-clause"><span>The finally Clause</span></a></h2><ul><li>Can appear at the end of a <code>try</code> construct</li><li>If <code>try</code> clause throws no exceptions, the <code>finally</code> clause is executed before execution continues after the <code>try</code> construct</li><li>Form:</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token comment">//** More handlers finally finally</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Purpose: To specify code that is to be executed, regardless of what happens in the <code>try</code> construct</li><li>[EX] file must be closed</li><li>A <code>try</code> construct with a <code>finally</code> clause can be used outside exception handling</li><li>This makes sense, of course, only if the compound statement has a <code>throw</code>, <code>break</code>, <code>continue</code>, or <code>return</code> statement</li></ul><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">try</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token punctuation">(</span>index <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> index <span class="token operator">&lt;</span> <span class="token number">100</span><span class="token punctuation">;</span> index<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">…</span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>…<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">return</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token comment">//** end of if</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token comment">//** end of try clause</span></span>
<span class="line"><span class="token keyword">finally</span> <span class="token punctuation">{</span></span>
<span class="line">…</span>
<span class="line"><span class="token punctuation">}</span> <span class="token comment">//** end of try construct</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="assertions" tabindex="-1"><a class="header-anchor" href="#assertions"><span>Assertions</span></a></h2><ul><li>Statements in the program declaring a boolean expression regarding the current state of the computation</li><li>Used for defensive programming</li><li>When evaluated to true nothing happens</li><li>When evaluated to false an <code>AssertionError</code> exception is thrown</li><li>Can be disabled during runtime without program modification or recompilation</li><li>Two forms</li><li><code>assert condition;</code></li><li><code>assert condition: expression;</code></li><li>Expression is passed to the <code>AssertionError</code> constructor as a string and becomes debugging output</li></ul><h2 id="evaluation-2" tabindex="-1"><a class="header-anchor" href="#evaluation-2"><span>Evaluation</span></a></h2><ul><li>The types of exceptions makes more sense than in the case of C++</li><li>Only objects that are instances of <code>Throwable</code> or some class that descends from it can be thrown</li><li>The <code>throws</code> clause is better than that of C++ (The <code>throw</code> clause in C++ says little to the programmer)</li><li>Method that does not include a <code>throws</code> clause cannot throw any checked exception</li><li>The <code>finally</code> clause is often useful</li><li>The Java interpreter throws a variety of exceptions that can be handled by user programs</li><li>Implicitly throws predefined exceptions</li></ul><h2 id="exception-handling-in-python" tabindex="-1"><a class="header-anchor" href="#exception-handling-in-python"><span>Exception Handling in Python</span></a></h2><ul><li>Exceptions are objects; the base class is <code>BaseException</code></li><li>All predefined and user-defined exceptions are derived from <code>Exception</code></li><li>Predefined subclasses of <code>Exception</code> are <code>ArithmeticError</code> (subclasses are <code>OverflowError</code>, <code>ZeroDivisionError</code>, and <code>FloatingPointError</code>) and <code>LookupError</code> (subclasses are <code>IndexError</code> and <code>KeyError</code>)</li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">try</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token comment"># The try block</span></span>
<span class="line"><span class="token keyword">except</span> Exception1<span class="token punctuation">:</span></span>
<span class="line"><span class="token comment"># Handler for Exception1</span></span>
<span class="line"><span class="token keyword">except</span> Exception2<span class="token punctuation">:</span></span>
<span class="line"><span class="token comment"># Handler for Exception2</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token keyword">else</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token comment"># The else block (no exception is raised)</span></span>
<span class="line"><span class="token keyword">finally</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token comment"># the finally block (do it no matter what)</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Handlers handle the named exception plus all subclasses of that exception, so if the named exception is <code>Exception</code>, it handlers all predefined and user-defined exceptions</li><li>Unhandled exceptions are propagated to the nearest enclosing <code>try</code> block; if no handler is found, the default handler is called</li><li><code>Raise IndexError</code> creates an instance</li><li>The raised exception object can be gotten:</li><li><code>except Exception as ex_obj:</code></li><li>The <code>assert</code> statement tests its Boolean expression (first parameter) and sends its second parameter to the constructor for the exception object to be raised</li><li><code>assert test, data</code></li></ul><h2 id="exception-handling-in-ruby" tabindex="-1"><a class="header-anchor" href="#exception-handling-in-ruby"><span>Exception Handling in Ruby</span></a></h2><ul><li>Exceptions are objects</li><li>There are many predefined exceptions</li><li>All exceptions that are user handled are either <code>StandardError</code> class or a subclass of it</li><li><code>StandardError</code> is derived from <code>Exception</code>, which has two methods, <code>message</code> and <code>backtrace</code></li><li>Exceptions can be raised with <code>raise</code>, which often has the form:</li><li><code>raise ″bad parameter″ if count == 0</code></li><li>Handlers are placed at the end of a <code>begin end</code> block of code; introduced by <code>rescue</code></li></ul><div class="language-ruby line-numbers-mode" data-highlighter="prismjs" data-ext="rb"><pre><code class="language-ruby"><span class="line"><span class="token keyword">begin</span></span>
<span class="line"><span class="token operator">-</span> Statements <span class="token keyword">in</span> the block</span>
<span class="line"><span class="token keyword">rescue</span></span>
<span class="line"><span class="token operator">-</span> Handler</span>
<span class="line"><span class="token keyword">end</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>The block could include <code>else</code> and/or <code>ensure</code> clauses, which are like <code>else</code> and <code>finally</code> in Java</li><li>Unlike the other languages we have discussed, in Ruby the code that raised an exception can be rerun by placing a <code>retry</code> statement at the end of the handler</li></ul><h2 id="introduction-to-event-handling" tabindex="-1"><a class="header-anchor" href="#introduction-to-event-handling"><span>Introduction to Event Handling</span></a></h2><ul><li>Similar to exception handling</li><li>An event is a notification that something specific has occurred, such as a mouse click on a graphical button (user interactions)</li><li>Through widgets</li><li>The event handler is a segment of code that is executed in response to an event</li><li>Event-driven programming was being used before GUIs</li><li>There are other uses such as Web server</li></ul><h2 id="java-swing-gui-components" tabindex="-1"><a class="header-anchor" href="#java-swing-gui-components"><span>Java Swing GUI Components</span></a></h2><ul><li><code>javax.swing</code></li><li>Collection of classes and interfaces include GUI components or widgets</li><li>Text box is an object of class <code>JTextField</code></li><li><code>JTextField name = new JTextField(32);</code></li><li>Radio button is an object of class <code>JRadioButton</code></li><li><code>ButtonGroup payment = new ButtonGroup();</code></li><li><code>JRadioButton box1 = new JRadioButton(&quot;Visa&quot;, true);</code></li><li><code>JRadioButton box2 = new JRadioButton(&quot;Master Charge&quot;);</code></li><li><code>payment.add(box1);</code></li><li><code>payment.add(box2);</code></li><li>GUI components can be placed in a frame</li><li><code>JPanel myPanel = new JPanel();</code></li><li><code>myPanel.add(button1);</code></li><li>Layout manager objects are used to control the placement of components</li></ul><h2 id="the-java-event-model" tabindex="-1"><a class="header-anchor" href="#the-java-event-model"><span>The Java Event Model</span></a></h2><ul><li>User interactions with GUI components create events</li><li>Event listeners connect events to event handler</li><li>Event generator tells a listener of an event by sending a message</li><li>Event generator and listener are connected by event listener registration</li><li>Interface is used to make event handling methods conform to a standard protocol</li><li>Class that implements a listener must implement an interface for the listener</li><li>[EX of event class] <code>ItemEvent</code></li><li>About event of clicking a checkbox, a radio button, or a list item</li><li>[Interface] <code>ItemListener</code> prescribes a method, <code>itemStateChanged</code></li><li>A handler for <code>ItemEvent</code> events</li><li>Should be implemented</li><li>Register listener</li><li><code>button1.addItemListener(this);</code></li><li>Each event handler can receives parameters</li><li>[EX] <code>isSelected</code></li></ul><h2 id="the-java-ex" tabindex="-1"><a class="header-anchor" href="#the-java-ex"><span>The Java EX</span></a></h2><div class="language-java line-numbers-mode" data-highlighter="prismjs" data-ext="java"><pre><code class="language-java"><span class="line"><span class="token keyword">package</span> <span class="token namespace">radiob</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>awt<span class="token punctuation">.</span></span><span class="token operator">*</span></span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>awt<span class="token punctuation">.</span>event<span class="token punctuation">.</span></span><span class="token operator">*</span></span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">import</span> <span class="token import"><span class="token namespace">javax<span class="token punctuation">.</span>swing<span class="token punctuation">.</span></span><span class="token operator">*</span></span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">RadioB</span> <span class="token keyword">extends</span> <span class="token class-name">JPanel</span> <span class="token keyword">implements</span> <span class="token class-name">ItemListener</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token class-name">JTextField</span> text<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token class-name">Font</span> plainFont<span class="token punctuation">,</span> boldFont<span class="token punctuation">,</span> italicFont<span class="token punctuation">,</span> boldItalicFont<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token class-name">JRadioButton</span> plain<span class="token punctuation">,</span> bold<span class="token punctuation">,</span> italic<span class="token punctuation">,</span> boldItalic<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token class-name">ButtonGroup</span> radioButtons<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token comment">// Define required widget</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token class-name">RadioB</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">text <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">JTextField</span><span class="token punctuation">(</span><span class="token string">&quot;In what font style should I appear?&quot;</span><span class="token punctuation">,</span> <span class="token number">25</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">text<span class="token punctuation">.</span><span class="token function">setFont</span><span class="token punctuation">(</span>plainFont<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">…</span>
<span class="line">plain <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">JRadioButton</span><span class="token punctuation">(</span><span class="token string">&quot;Plain&quot;</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">bold <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">JRadioButton</span><span class="token punctuation">(</span><span class="token string">&quot;Bold&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">…</span>
<span class="line">radioButtons<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>plain<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">radioButtons<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>bold<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">…</span>
<span class="line"><span class="token class-name">JPanel</span> radioPanel <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">JPanel</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// Put widgets together</span></span>
<span class="line">radioPanel<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>text<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">radioPanel<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>plain<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">radioPanel<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>bold<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token comment">// Register the event handlers</span></span>
<span class="line">plain<span class="token punctuation">.</span><span class="token function">addItemListener</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">bold<span class="token punctuation">.</span><span class="token function">addItemListener</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token comment">// Create the fonts</span></span>
<span class="line">plainFont <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Font</span><span class="token punctuation">(</span><span class="token string">&quot;Serif&quot;</span><span class="token punctuation">,</span> <span class="token class-name">Font</span><span class="token punctuation">.</span><span class="token constant">PLAIN</span><span class="token punctuation">,</span> <span class="token number">16</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">boldFont <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Font</span><span class="token punctuation">(</span><span class="token string">&quot;Serif&quot;</span><span class="token punctuation">,</span> <span class="token class-name">Font</span><span class="token punctuation">.</span><span class="token constant">BOLD</span><span class="token punctuation">,</span> <span class="token number">16</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token comment">// End of the constructor</span></span>
<span class="line"><span class="token comment">// The event handler</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">void</span> itemStateChanged <span class="token punctuation">(</span><span class="token class-name">ItemEvent</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">// Determine which button is on and set the font</span></span>
<span class="line"><span class="token comment">// accordingly</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>plain<span class="token punctuation">.</span><span class="token function">isSelected</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">text<span class="token punctuation">.</span><span class="token function">setFont</span><span class="token punctuation">(</span>plainFont<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>bold<span class="token punctuation">.</span><span class="token function">isSelected</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">text<span class="token punctuation">.</span><span class="token function">setFont</span><span class="token punctuation">(</span>boldFont<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>italic<span class="token punctuation">.</span><span class="token function">isSelected</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">text<span class="token punctuation">.</span><span class="token function">setFont</span><span class="token punctuation">(</span>italicFont<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>boldItalic<span class="token punctuation">.</span><span class="token function">isSelected</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">text<span class="token punctuation">.</span><span class="token function">setFont</span><span class="token punctuation">(</span>boldItalicFont<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token comment">// End of itemStateChanged</span></span>
<span class="line"><span class="token comment">// The main method</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">// Create the window frame</span></span>
<span class="line"><span class="token class-name">JFrame</span> myFrame <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">JFrame</span><span class="token punctuation">(</span><span class="token string">&quot; Radio button example&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// Create the content pane and set it to the frame</span></span>
<span class="line"><span class="token class-name">JComponent</span> myContentPane <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">RadioB</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">myContentPane<span class="token punctuation">.</span><span class="token function">setOpaque</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">myFrame<span class="token punctuation">.</span><span class="token function">setContentPane</span><span class="token punctuation">(</span>myContentPane<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// Display the window.</span></span>
<span class="line">myFrame<span class="token punctuation">.</span><span class="token function">pack</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">myFrame<span class="token punctuation">.</span><span class="token function">setVisible</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token comment">// End of RadioB</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="event-handling-in-c" tabindex="-1"><a class="header-anchor" href="#event-handling-in-c"><span>Event Handling in C#</span></a></h2><ul><li>Similar to Java</li><li>.NET has two approaches: Windows Forms, Windows Presentation Foundation</li><li>In Windows Forms, GUI can be constructed by <code>System.Windows.Forms</code></li><li>Implicitly provides a window - No need to build frame or panel explicitly</li><li>Label objects: place text in the window</li><li><code>RadioButton</code> class: define radio button objects</li><li>Components are positioned by assigning a new <code>Point</code> object to the <code>Location</code> property of the component (<code>System.Drawing</code>)</li></ul><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">private</span> <span class="token class-name">RadioButton</span> plain <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">RadioButton</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">plain<span class="token punctuation">.</span>Location <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">Point</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">plain<span class="token punctuation">.</span>Text <span class="token operator">=</span> ″Plain″<span class="token punctuation">;</span></span>
<span class="line">controls<span class="token punctuation">.</span><span class="token function">Add</span><span class="token punctuation">(</span>plain<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>All C# event handlers have the same protocol, the return type is void and the two parameters are of types <code>object</code> and <code>EventArgs</code></li><li>An event handler can have any name</li><li>A radio button is tested with the Boolean <code>Checked</code> property of the button</li></ul><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> rb_CheckedChanged <span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">object</span></span> o<span class="token punctuation">,</span> <span class="token class-name">EventArgs</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>plain<span class="token punctuation">.</span>Checked<span class="token punctuation">)</span> …</span>
<span class="line"><span class="token range operator">..</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>To register an event, a new <code>EventHandler</code> object must be created and added to the predefined delegate for the event</li><li>If the handler was named <code>rb_CheckedChanged</code>, register it on the radio button named plain with: <code>plain.CheckedChanged += new EventHandler (rb_CheckedChanged);</code></li><li>When a radio button changes from unchecked to checked, <code>CheckedChanged</code> event is raised</li><li>The associated delegate is referenced by the name of the event</li></ul><h2 id="the-c-ex" tabindex="-1"><a class="header-anchor" href="#the-c-ex"><span>The C# EX</span></a></h2><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">namespace</span> <span class="token namespace">RadioB</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">using</span> <span class="token namespace">System</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">using</span> <span class="token namespace">System<span class="token punctuation">.</span>Drawing</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">using</span> <span class="token namespace">System<span class="token punctuation">.</span>Windows<span class="token punctuation">.</span>Forms</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">RadioB</span> <span class="token punctuation">:</span> <span class="token type-list"><span class="token class-name">Form</span></span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token class-name">Label</span> text <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">Label</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token class-name">RadioButton</span> plain <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">RadioButton</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token class-name">RadioButton</span> bold <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">RadioButton</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">…</span>
<span class="line"><span class="token comment">// Define required widget</span></span>
<span class="line"><span class="token keyword">public</span> <span class="token function">RadioB</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">// Initialize the attributes of the text and radio buttons</span></span>
<span class="line">text<span class="token punctuation">.</span>AutoSize <span class="token operator">=</span> <span class="token boolean">true</span><span class="token punctuation">;</span></span>
<span class="line">text<span class="token punctuation">.</span>Text <span class="token operator">=</span> <span class="token string">&quot;In what font style should I appear?&quot;</span><span class="token punctuation">;</span></span>
<span class="line">plain<span class="token punctuation">.</span>Location <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">Point</span><span class="token punctuation">(</span><span class="token number">220</span><span class="token punctuation">,</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">plain<span class="token punctuation">.</span>Text <span class="token operator">=</span> <span class="token string">&quot;Plain&quot;</span><span class="token punctuation">;</span></span>
<span class="line">plain<span class="token punctuation">.</span>Checked <span class="token operator">=</span> <span class="token boolean">true</span><span class="token punctuation">;</span></span>
<span class="line">…</span>
<span class="line">…</span>
<span class="line">Controls<span class="token punctuation">.</span><span class="token function">Add</span><span class="token punctuation">(</span>text<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">Controls<span class="token punctuation">.</span><span class="token function">Add</span><span class="token punctuation">(</span>plain<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// Put widgets together</span></span>
<span class="line"><span class="token range operator">..</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token comment">// Register the event handler for the radio buttons</span></span>
<span class="line">plain<span class="token punctuation">.</span>CheckedChanged <span class="token operator">+=</span></span>
<span class="line"><span class="token keyword">new</span> <span class="token constructor-invocation class-name">EventHandler</span><span class="token punctuation">(</span>rb_CheckedChanged<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">bold<span class="token punctuation">.</span>CheckedChanged <span class="token operator">+=</span></span>
<span class="line"><span class="token keyword">new</span> <span class="token constructor-invocation class-name">EventHandler</span><span class="token punctuation">(</span>rb_CheckedChanged<span class="token punctuation">)</span></span>
<span class="line"><span class="token range operator">..</span><span class="token punctuation">.</span></span>
<span class="line"><span class="token punctuation">}</span> <span class="token comment">// End of the constructor</span></span>
<span class="line"><span class="token comment">// The main method is where execution begins</span></span>
<span class="line"><span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">Main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">Application<span class="token punctuation">.</span><span class="token function">EnableVisualStyles</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">Application<span class="token punctuation">.</span><span class="token function">SetCompatibleTextRenderingDefault</span><span class="token punctuation">(</span><span class="token boolean">false</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">Application<span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token constructor-invocation class-name">RadioB</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token comment">// The event handler</span></span>
<span class="line"><span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> rb_CheckedChanged <span class="token punctuation">(</span> <span class="token class-name"><span class="token keyword">object</span></span> o<span class="token punctuation">,</span> <span class="token class-name">EventArgs</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line"><span class="token comment">// Determine which button is on and set the font</span></span>
<span class="line"><span class="token comment">// accordingly</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>plain<span class="token punctuation">.</span>Checked<span class="token punctuation">)</span></span>
<span class="line">text<span class="token punctuation">.</span>Font <span class="token operator">=</span></span>
<span class="line"><span class="token keyword">new</span> <span class="token constructor-invocation class-name">Font</span><span class="token punctuation">(</span> text<span class="token punctuation">.</span>Font<span class="token punctuation">.</span>Name<span class="token punctuation">,</span> text<span class="token punctuation">.</span>Font<span class="token punctuation">.</span>Size<span class="token punctuation">,</span> FontStyle<span class="token punctuation">.</span>Regular<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">…</span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="event-handling-in-python" tabindex="-1"><a class="header-anchor" href="#event-handling-in-python"><span>Event Handling in Python</span></a></h2><ul><li><code>tkinter</code> is a module required when developing a graphical user interface (GUI) in Python.</li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">from</span> tkinter <span class="token keyword">import</span> <span class="token operator">*</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">callback</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">button<span class="token punctuation">[</span><span class="token string">&quot;text&quot;</span><span class="token punctuation">]</span> <span class="token operator">=</span><span class="token string">&quot;버튼이 클릭되었음!&quot;</span></span>
<span class="line">window <span class="token operator">=</span> Tk<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">button <span class="token operator">=</span> Button<span class="token punctuation">(</span>window<span class="token punctuation">,</span> text<span class="token operator">=</span><span class="token string">&quot;클릭&quot;</span><span class="token punctuation">,</span> command<span class="token operator">=</span>callback<span class="token punctuation">)</span></span>
<span class="line">button<span class="token punctuation">.</span>pack<span class="token punctuation">(</span>side<span class="token operator">=</span>LEFT<span class="token punctuation">)</span></span>
<span class="line">window<span class="token punctuation">.</span>mainloop<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Widgets in <code>tkinter</code></li><li>Button</li><li>Canvas</li><li>Checkbutton</li><li>Entry</li><li>Frame</li><li>Label</li><li>Listbox</li><li>Menu</li><li>Menubutton</li><li>Message</li><li>Radiobutton</li><li>Scale</li><li>Scrollbar</li><li>Text</li><li>Toplevel</li><li>LabelFrame</li><li>PanedWindow</li><li>Calculator</li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">from</span> tkinter <span class="token keyword">import</span> <span class="token operator">*</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">click</span><span class="token punctuation">(</span>key<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token keyword">if</span> key <span class="token operator">==</span> <span class="token string">&#39;=&#39;</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token comment"># If it is the “=” button,</span></span>
<span class="line"><span class="token keyword">try</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token comment">#the formula is calculated and the result is displayed</span></span>
<span class="line">result <span class="token operator">=</span> <span class="token builtin">eval</span><span class="token punctuation">(</span>entry<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">entry<span class="token punctuation">.</span>delete<span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> END<span class="token punctuation">)</span></span>
<span class="line">entry<span class="token punctuation">.</span>insert<span class="token punctuation">(</span>END<span class="token punctuation">,</span> <span class="token builtin">str</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">except</span><span class="token punctuation">:</span></span>
<span class="line">entry<span class="token punctuation">.</span>insert<span class="token punctuation">(</span>END<span class="token punctuation">,</span> <span class="token string">&quot;오류!&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">elif</span> key <span class="token operator">==</span> <span class="token string">&#39;C&#39;</span><span class="token punctuation">:</span></span>
<span class="line">entry<span class="token punctuation">.</span>delete<span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> END<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">else</span><span class="token punctuation">:</span></span>
<span class="line">entry<span class="token punctuation">.</span>insert<span class="token punctuation">(</span>END<span class="token punctuation">,</span> key<span class="token punctuation">)</span></span>
<span class="line">window <span class="token operator">=</span> Tk<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">window<span class="token punctuation">.</span>title<span class="token punctuation">(</span><span class="token string">&quot;간단한 계산기&quot;</span><span class="token punctuation">)</span></span>
<span class="line">buttons <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line"><span class="token string">&#39;7&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;8&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;9&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;+&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;C&#39;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token string">&#39;4&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;5&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;6&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;-&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39; &#39;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token string">&#39;1&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;2&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;3&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;*&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39; &#39;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token string">&#39;0&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;.&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;=&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;/&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39; &#39;</span> <span class="token punctuation">]</span></span>
<span class="line"><span class="token comment"># # Create a button using a loop</span></span>
<span class="line">i<span class="token operator">=</span><span class="token number">0</span></span>
<span class="line"><span class="token keyword">for</span> b <span class="token keyword">in</span> buttons<span class="token punctuation">:</span></span>
<span class="line">cmd <span class="token operator">=</span> <span class="token keyword">lambda</span> x<span class="token operator">=</span>b<span class="token punctuation">:</span> click<span class="token punctuation">(</span>x<span class="token punctuation">)</span></span>
<span class="line">b <span class="token operator">=</span> Button<span class="token punctuation">(</span>window<span class="token punctuation">,</span>text<span class="token operator">=</span>b<span class="token punctuation">,</span>width<span class="token operator">=</span><span class="token number">5</span><span class="token punctuation">,</span>relief<span class="token operator">=</span><span class="token string">&#39;ridge&#39;</span><span class="token punctuation">,</span>command<span class="token operator">=</span>cmd<span class="token punctuation">)</span></span>
<span class="line">b<span class="token punctuation">.</span>grid<span class="token punctuation">(</span>row<span class="token operator">=</span>i<span class="token operator">//</span><span class="token number">5</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">,</span>column<span class="token operator">=</span>i<span class="token operator">%</span><span class="token number">5</span><span class="token punctuation">)</span></span>
<span class="line">i <span class="token operator">+=</span> <span class="token number">1</span></span>
<span class="line"><span class="token comment"># The entry widget is placed across five cells in the top row</span></span>
<span class="line">entry <span class="token operator">=</span> Entry<span class="token punctuation">(</span>window<span class="token punctuation">,</span> width<span class="token operator">=</span><span class="token number">33</span><span class="token punctuation">,</span> bg<span class="token operator">=</span><span class="token string">&quot;yellow&quot;</span><span class="token punctuation">)</span></span>
<span class="line">entry<span class="token punctuation">.</span>grid<span class="token punctuation">(</span>row<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> column<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> columnspan<span class="token operator">=</span><span class="token number">5</span><span class="token punctuation">)</span></span>
<span class="line">window<span class="token punctuation">.</span>mainloop<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Event handler binding</li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">from</span> tkinter <span class="token keyword">import</span> <span class="token operator">*</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">sleft</span><span class="token punctuation">(</span>event<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;단일 클릭, 왼쪽 버튼&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">dleft</span><span class="token punctuation">(</span>event<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;더블 클릭, 왼쪽 버튼&quot;</span><span class="token punctuation">)</span></span>
<span class="line">widget <span class="token operator">=</span> Button<span class="token punctuation">(</span><span class="token boolean">None</span><span class="token punctuation">,</span> text<span class="token operator">=</span><span class="token string">&#39;마우스 클릭&#39;</span><span class="token punctuation">)</span></span>
<span class="line">widget<span class="token punctuation">.</span>pack<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">widget<span class="token punctuation">.</span>bind<span class="token punctuation">(</span><span class="token string">&#39;&lt;Button-1&gt;&#39;</span><span class="token punctuation">,</span> sleft<span class="token punctuation">)</span></span>
<span class="line">widget<span class="token punctuation">.</span>bind<span class="token punctuation">(</span><span class="token string">&#39;&lt;Double-1&gt;&#39;</span><span class="token punctuation">,</span> dleft<span class="token punctuation">)</span></span>
<span class="line">widget<span class="token punctuation">.</span>mainloop<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>&lt;Button-1&gt;</code></li><li><code>&lt;B1-Motion&gt;</code></li><li><code>&lt;ButtonRelease-1&gt;</code></li><li><code>&lt;Double-Button-1&gt;</code></li><li><code>&lt;Enter&gt;</code></li><li><code>&lt;Leave&gt;</code></li><li><code>&lt;FocusIn&gt;</code> 단일 클릭, 왼쪽 버튼 더블 클릭, 왼쪽 버튼</li><li><code>&lt;FocusOut&gt;</code></li><li><code>&lt;Return&gt;</code></li><li><code>&lt;Key&gt;</code></li><li><code>&lt;Shift-Up&gt;</code></li><li><code>&lt;Configure&gt;</code></li></ul><h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary"><span>Summary</span></a></h2><ul><li>Ada provides extensive exception-handling facilities with a comprehensive set of built-in exceptions</li><li>C++ includes no predefined exceptions</li><li>Exceptions are bound to handlers by connecting the type of expression in the <code>throw</code> statement to that of the formal parameter of the <code>catch</code> function</li><li>Java exceptions are similar to C++ exceptions except that a Java exception must be a descendant of the <code>Throwable</code> class. Additionally Java includes a <code>finally</code> clause</li><li>An event is a notification that something has occurred that requires handling by an event handler</li><li>Java event handling is defined on the Swing components</li><li>C# event handling is the .NET model, which is similar to the Java model</li></ul>`,104))])}const k=e(c,[["render",d]]),h=JSON.parse('{"path":"/pl/14-Exception-Handling-and-Event-Handling.html","title":"14. Exception Handling and Event Handling","lang":"ko-KR","frontmatter":{"description":"14. Exception Handling and Event Handling","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"14. Exception Handling and Event Handling\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-11T17:33:49.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/pl/14-Exception-Handling-and-Event-Handling.html"}],["meta",{"property":"og:title","content":"14. Exception Handling and Event Handling"}],["meta",{"property":"og:description","content":"14. Exception Handling and Event Handling"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-11T17:33:49.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-11T17:33:49.000Z"}]]},"git":{"createdTime":1781199229000,"updatedTime":1781199229000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":2,"url":"https://github.com/kmbzn"}],"changelog":[{"hash":"93aaec14aeb23243f14a468bc423e7f688a54750","time":1781199229000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: add Programming Languages section to sidebar and publish pl/ docs","coAuthors":[{"name":"kmbzn","email":"kmbzn24@gmail.com"}]}]},"filePathRelative":"pl/14-Exception-Handling-and-Event-Handling.md","autoDesc":true}');export{k as comp,h as data};
